beforeSaveCustomScript:
// Call automatiche da Appuntamento Pending: campi impostati in PHP (skipHooks).
if (nota == null || !string\contains(nota, 'Auto-Pending-Appuntamento:')) {

// Aggiorna Data (solo se dateStart valorizzato)
ifThen(
    !empty(dateStart),
    data = datetime\format((datetime\addHours(dateStart, 0)), 'Europe/Amsterdam', 'DD/MM/YYYY HH:mm')
);
dateEnd = null;

// Aggiorna Prospect
$prospectId = record\findOne('Prospect', null, null, 'name=', parentName);

if ($prospectId) {
    prospectId = $prospectId
}


// Telefono: conserva valore inserito in creazione, altrimenti da Prospect
if (telefono == null || telefono == '') {
    telefono = prospect.phoneNumber;
}

whatsAppNumero = string\concatenate('https://wa.me/', '+39', telefono);
name = string\upperCase(string\concatenate(data, ' - ', tipologia, ' - ', parentName, ' - ', telefono));

}
